// Learn: Submit Callable work to an ExecutorService.
import java.util.concurrent.Callable;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

ConcurrentHashMap<String, Integer> counts = new ConcurrentHashMap<>();
ExecutorService pool = Executors.newFixedThreadPool(2);
Callable<Integer> task = () -> counts.merge("ok", 1, Integer::sum);
// submit returns a Future for the Callable result.
Future<Integer> result = pool.submit(task);
try {
  // get() blocks for the result; real code also handles its checked exceptions.
  System.out.println(result.get());
} finally {
  pool.shutdown();
}
